int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

void nw_kernel1(const int* referrence,
                const int* matrix_cuda,
                int* output_matrix,
                int cols,
                int penalty,
                int i,
                int block_width,
                int worksize,
                int offset_r,
                int offset_c,
                volatile int* temp,
                volatile int* ref)
{
    int bx = get_global_id(0) / BLOCK_SIZE;
    int tx = get_global_id(0) % BLOCK_SIZE;

    int b_index_x = bx;
    int b_index_y = i - 1 - bx;

    int base_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
    int index   = base_index + tx + (cols + 1);
    int index_n   = base_index + tx + 1;
    int index_w   = base_index + cols;
    int index_nw =  base_index;

    int local_idx = tx;

    if (tx == 0)
        temp[0] = matrix_cuda[index_nw];

    for (int ty = 0; ty < BLOCK_SIZE; ty++)
        ref[ty * BLOCK_SIZE + tx] = referrence[index + cols * ty];

    barrier(CLK_LOCAL_MEM_FENCE);

    temp[(tx + 1) * (BLOCK_SIZE + 1)] = matrix_cuda[index_w + cols * tx];

    barrier(CLK_LOCAL_MEM_FENCE);

    temp[tx + 1] = matrix_cuda[index_n];

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int m = 0; m < BLOCK_SIZE; m++) {
        if (tx <= m) {
            int t_index_x = tx + 1;
            int t_index_y = m - tx + 1;

            int val_diag = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x - 1)];
            int val_left = temp[(t_index_y) * (BLOCK_SIZE + 1) + (t_index_x - 1)];
            int val_up   = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x)];
            int ref_val  = ref[(t_index_y - 1) * BLOCK_SIZE + (t_index_x - 1)];

            temp[t_index_y * (BLOCK_SIZE + 1) + t_index_x] = maximum(val_diag + ref_val,
                                                                     val_left - penalty,
                                                                     val_up - penalty);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        if (tx <= m) {
            int t_index_x = tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - tx;

            int val_diag = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x - 1)];
            int val_left = temp[(t_index_y) * (BLOCK_SIZE + 1) + (t_index_x - 1)];
            int val_up   = temp[(t_index_y - 1) * (BLOCK_SIZE + 1) + (t_index_x)];
            int ref_val  = ref[(t_index_y - 1) * BLOCK_SIZE + (t_index_x - 1)];

            temp[t_index_y * (BLOCK_SIZE + 1) + t_index_x] = maximum(val_diag + ref_val,
                                                                     val_left - penalty,
                                                                     val_up - penalty);
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    for (int ty = 0; ty < BLOCK_SIZE; ty++)
        output_matrix[index + ty * cols] = temp[(ty + 1) * (BLOCK_SIZE + 1) + tx + 1];
}

